SELECT cache_id, event_id, window_months, region_signature, result_json, created_at
FROM analysis_cache
WHERE cache_id = #{cacheId}

SELECT cache_id, event_id, window_months, region_signature, result_json, created_at
FROM analysis_cache
WHERE event_id         = #{eventId}
  AND window_months    = #{windowMonths}
  AND region_signature = #{regionSignature}
